24	export function buildInputField(field: DMMF.SchemaArg, context: GenerateContext, source?: string): ts.Property {
25	  const tsType = buildAllFieldTypes(field.inputTypes, context, source)
26	
27	  const tsProperty = ts.property(field.name, field.isRequired ? tsType : appendSkipType(context, tsType))
28	  if (!field.isRequired) {
29	    tsProperty.optional()
30	  }
31	  const docComment = ts.docComment()
32	  if (field.comment) {
33	    docComment.addText(field.comment)
34	  }
35	  if (field.deprecation) {
36	    docComment.addText(`@deprecated since ${field.deprecation.sinceVersion}: ${field.deprecation.reason}`)
37	  }
38	
39	  if (docComment.lines.length > 0) {
40	    tsProperty.setDocComment(docComment)
41	  }
42	
43	  return tsProperty
44	}
