46	function buildSingleFieldType(t: DMMF.InputTypeRef, genericsInfo: GenericArgsInfo, source?: string): ts.TypeBuilder {
47	  let type: ts.NamedType
48	
49	  const scalarType = GraphQLScalarToJSTypeTable[t.type]
50	  if (t.location === 'enumTypes' && t.namespace === 'model') {
51	    type = ts.namedType(`$Enums.${t.type}`)
52	  } else if (t.type === 'Null') {
53	    return ts.nullType
54	  } else if (Array.isArray(scalarType)) {
55	    const union = ts.unionType(scalarType.map(namedInputType))
56	    if (t.isList) {
57	      return union.mapVariants((variant) => ts.array(variant))
58	    }
59	    return union
60	  } else if (t.namespace === 'prisma') {
61	    type = namedInputType(`Prisma.${t.type}`)
62	  } else {
63	    type = namedInputType(scalarType ?? t.type)
64	  }
65	
66	  if (genericsInfo.typeRefNeedsGenericModelArg(t)) {
67	    if (source) {
68	      type.addGenericArgument(ts.stringLiteral(source))
69	    } else {
70	      type.addGenericArgument(ts.namedType('$PrismaModel'))
71	    }
72	  }
73	
74	  if (t.isList) {
75	    return ts.array(type)
76	  }
77	
78	  return type
79	}
