81	function namedInputType(typeName: string) {
82	  const typeNameParts = typeName.split('.')
83	  const typeNameWithoutNamespace = typeNameParts[typeNameParts.length - 1]
84	  const mappedInputTypeName = JSOutputTypeToInputType[typeNameWithoutNamespace] ?? typeNameWithoutNamespace
85	  return ts.namedType(typeNameParts.slice(0, -1).concat(mappedInputTypeName).join('.'))
86	}
