import type { Field, Model } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/** Maps a Prisma scalar type name to a TypeScript type. */
export function mapScalarType(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? 'unknown'
}

/** Returns the TypeScript type string for a DMMF field. */
export function fieldToTsType(field: Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }
  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Generates a TypeScript interface declaration from a DMMF model. */
export function generateModelInterface(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => `  ${f.name}: ${fieldToTsType(f)}`)
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Generates the input type for creating a model instance (omits auto-generated fields). */
export function generateCreateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue || f.isId || f.isUpdatedAt
      const tsType = fieldToTsType(f)
      return `  ${f.name}${optional ? '?' : ''}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Generates the input type for updating a model instance (all fields optional). */
export function generateUpdateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => `  ${f.name}?: ${fieldToTsType(f)}`)
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/** Generates the where-unique input type based on the model's unique/id fields. */
export function generateWhereUniqueInput(model: Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)

  if (uniqueFields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }

  const fields = uniqueFields.map((f) => `  ${f.name}?: ${fieldToTsType(f)}`).join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

/** Generates a typed REST client class for a single model. */
export function generateModelClient(model: Model): string {
  const name = model.name
  const resourcePath = name.toLowerCase()

  return `export class ${name}Client {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  async findMany(): Promise<${name}[]> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (!response.ok) {
      throw new Error(\`Failed to fetch ${name} list: \${response.statusText}\`)
    }
    return response.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const key = Object.entries(where).find(([, v]) => v !== undefined)
    if (!key) {
      throw new Error('At least one unique field must be provided')
    }
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${encodeURIComponent(String(key[1]))}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (response.status === 404) {
      return null
    }
    if (!response.ok) {
      throw new Error(\`Failed to fetch ${name}: \${response.statusText}\`)
    }
    return response.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    })
    if (!response.ok) {
      throw new Error(\`Failed to create ${name}: \${response.statusText}\`)
    }
    return response.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const key = Object.entries(where).find(([, v]) => v !== undefined)
    if (!key) {
      throw new Error('At least one unique field must be provided')
    }
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${encodeURIComponent(String(key[1]))}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    })
    if (!response.ok) {
      throw new Error(\`Failed to update ${name}: \${response.statusText}\`)
    }
    return response.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const key = Object.entries(where).find(([, v]) => v !== undefined)
    if (!key) {
      throw new Error('At least one unique field must be provided')
    }
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${encodeURIComponent(String(key[1]))}\`, {
      method: 'DELETE',
      headers: this.#headers,
    })
    if (!response.ok) {
      throw new Error(\`Failed to delete ${name}: \${response.statusText}\`)
    }
    return response.json() as Promise<${name}>
  }
}`
}

/** Generates the top-level REST client class that aggregates all model clients. */
export function generateRestClient(models: readonly Model[]): string {
  const properties = models
