import type { Field, Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import {
  fieldToTsType,
  generateCreateInput,
  generateModelClient,
  generateModelInterface,
  generateRestClient,
  generateUpdateInput,
  generateWhereUniqueInput,
  mapScalarType,
} from './template'

function createField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

function createModel(overrides: Partial<Model>): Model {
  return {
    name: 'User',
    dbName: null,
    schema: null,
    fields: [],
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as Model
}

describe('mapScalarType', () => {
  test('maps known Prisma scalar types', () => {
    expect(mapScalarType('String')).toBe('string')
    expect(mapScalarType('Boolean')).toBe('boolean')
    expect(mapScalarType('Int')).toBe('number')
    expect(mapScalarType('Float')).toBe('number')
    expect(mapScalarType('Decimal')).toBe('string')
    expect(mapScalarType('BigInt')).toBe('bigint')
    expect(mapScalarType('DateTime')).toBe('Date')
    expect(mapScalarType('Json')).toBe('unknown')
    expect(mapScalarType('Bytes')).toBe('Buffer')
  })

  test('returns unknown for unrecognized types', () => {
    expect(mapScalarType('SomeUnknown')).toBe('unknown')
  })
})

describe('fieldToTsType', () => {
  test('maps a required scalar field', () => {
    expect(fieldToTsType(createField({ type: 'Int', isRequired: true }))).toBe('number')
  })

  test('maps an optional scalar field', () => {
    expect(fieldToTsType(createField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('maps a list field', () => {
    expect(fieldToTsType(createField({ type: 'String', isList: true }))).toBe('string[]')
  })

  test('maps an enum field', () => {
    expect(fieldToTsType(createField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('maps an object (relation) field', () => {
    expect(fieldToTsType(createField({ kind: 'object', type: 'Post' }))).toBe('Post')
  })
})

describe('generateModelInterface', () => {
  test('generates an interface with scalar fields only', () => {
    const model = createModel({
      name: 'User',
      fields: [
        createField({ name: 'id', type: 'Int', isId: true }),
        createField({ name: 'email', type: 'String' }),
        createField({ name: 'name', type: 'String', isRequired: false }),
        createField({ name: 'posts', kind: 'object', type: 'Post', isList: true }),
      ],
    })

    const result = generateModelInterface(model)
    expect(result).toContain('export interface User')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
    expect(result).not.toContain('posts')
  })
})

describe('generateCreateInput', () => {
  test('marks id and default fields as optional', () => {
    const model = createModel({
      name: 'User',
      fields: [
        createField({ name: 'id', type: 'Int', isId: true }),
        createField({ name: 'email', type: 'String' }),
        createField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
      ],
    })

    const result = generateCreateInput(model)
    expect(result).toContain('export interface UserCreateInput')
    expect(result).toContain('id?: number')
    expect(result).toContain('email: string')
    expect(result).toContain('createdAt?: Date')
  })
})

describe('generateUpdateInput', () => {
  test('makes all fields optional', () => {
    const model = createModel({
      name: 'User',
      fields: [
        createField({ name: 'id', type: 'Int', isId: true }),
        createField({ name: 'email', type: 'String' }),
      ],
    })

    const result = generateUpdateInput(model)
    expect(result).toContain('export interface UserUpdateInput')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
  })
})

describe('generateWhereUniqueInput', () => {
  test('includes id and unique fields', () => {
    const model = createModel({
      name: 'User',
      fields: [
        createField({ name: 'id', type: 'Int', isId: true }),
        createField({ name: 'email', type: 'String', isUnique: true }),
        createField({ name: 'name', type: 'String' }),
      ],
    })

    const result = generateWhereUniqueInput(model)
    expect(result).toContain('export interface UserWhereUniqueInput')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toContain('name')
  })

  test('falls back to Record type when no unique fields exist', () => {
    const model = createModel({
      name: 'Log',
      fields: [createField({ name: 'message', type: 'String' })],
    })

    const result = generateWhereUniqueInput(model)
    expect(result).toContain('export type LogWhereUniqueInput = Record<string, unknown>')
  })
})

describe('generateModelClient', () => {
  test('generates a client class with CRUD methods', () => {
    const model = createModel({
      name: 'Post',
      fields: [
        createField({ name: 'id', type: 'Int', isId: true }),
        createField({ name: 'title', type: 'String' }),
      ],
    })

    const result = generateModelClient(model)
    expect(result).toContain('export class PostClient')
    expect(result).toContain('async findMany(): Promise<Post[]>')
    expect(result).toContain('async findUnique(where: PostWhereUniqueInput): Promise<Post | null>')
    expect(result).toContain('async create(data: PostCreateInput): Promise<Post>')
    expect(result).toContain('async update(where: PostWhereUniqueInput, data: PostUpdateInput): Promise<Post>')
    expect(result).toContain('async delete(where: PostWhereUniqueInput): Promise<Post>')
    expect(result).toContain('/post')
  })
})

describe('generateRestClient', () => {
  test('generates an aggregated client with model accessors', () => {
    const models = [
      createModel({ name: 'User', fields: [createField({ name: 'id', type: 'Int', isId: true })] }),
      createModel({ name: 'Post', fields: [createField({ name: 'id', type: 'Int', isId: true })] }),
    ]

    const result = generateRestClient(models)
    expect(result).toContain('export class RestClient')
    expect(result).toContain('readonly user: UserClient')
    expect(result).toContain('readonly post: PostClient')
    expect(result).toContain('new UserClient(baseUrl, headers)')
    expect(result).toContain('new PostClient(baseUrl, headers)')
  })
})

