#!/usr/bin/env node

import { generatorHandler } from '@prisma/generator-helper'

import { RestClientGenerator } from './generator'

const generator = new RestClientGenerator()

generatorHandler({
  onManifest(config) {
    return generator.getManifest(config)
  },
  async onGenerate(options) {
    await generator.generate(options)
  },
})

import fs from 'node:fs'
import path from 'node:path'

import type { Document } from '@prisma/dmmf'
import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import {
  generateCreateInput,
  generateFileHeader,
  generateModelClient,
  generateModelInterface,
  generateRestClient,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './template'

export class RestClientGenerator {
  readonly name = 'prisma-generator-rest-client'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated/rest-client',
      prettyName: 'Prisma REST Client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error('No output directory specified for prisma-generator-rest-client')
    }

    const code = generateRestClientCode(options.dmmf)

    await fs.promises.mkdir(outputDir, { recursive: true })
    await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
  }
}

/** Generates the complete REST client source file from the DMMF document. */
export function generateRestClientCode(dmmf: Document): string {
  const models = dmmf.datamodel.models

  const sections: string[] = [generateFileHeader()]

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
    sections.push(generateModelClient(model))
  }

  sections.push(generateRestClient(models))

  return sections.join('\n\n') + '\n'
}
